// Handles efficient loading and processing of 3D models

import * as THREE from 'three';
import { GLTFLoader } from 'three/examples/jsm/loaders/GLTFLoader';
import { DRACOLoader } from 'three/examples/jsm/loaders/DRACOLoader';
export class ModelLoader {
  constructor() {
    // Create GLTF loader with Draco compression support
    this.gltfLoader = new GLTFLoader();

    // Set up Draco loader for compressed models
    const dracoLoader = new DRACOLoader();
    dracoLoader.setDecoderPath('/draco/'); // Adjust if needed
    this.gltfLoader.setDRACOLoader(dracoLoader);

    // Cache for loaded models to avoid reloading
    this.modelCache = {};

    // Create loading manager to track progress
    this.loadingManager = new THREE.LoadingManager();
    this.loadingManager.onProgress = (url, loaded, total) => {
      // Dispatch loading progress event
      const event = new CustomEvent('model-loading-progress', {
        detail: {
          url,
          loaded,
          total,
          progress: loaded / total
        }
      });
      window.dispatchEvent(event);
    };

    // Assign loading manager to the loaders
    this.gltfLoader.manager = this.loadingManager;

    // Debug mode for logging
    this.debug = true;
  }

  /**
   * Load a 3D model
   * @param {string} modelType - Type of model (e.g., 'treadmill')
   * @param {string} modelPath - Path to the model file
   * @param {Function} onLoad - Callback when model is loaded
   * @param {Function} onError - Callback when loading fails
   */
  load(modelType, modelPath, onLoad, onError) {
    if (this.debug) console.log(`[ModelLoader] Loading: ${modelType} from ${modelPath}`);

    // Dispatch loading started event
    const startEvent = new CustomEvent('model-loading-started', {
      detail: {
        modelType,
        modelPath
      }
    });
    window.dispatchEvent(startEvent);

    // Check cache first
    if (this.modelCache[modelType]) {
      if (this.debug) console.log(`[ModelLoader] Using cached model: ${modelType}`);

      // Create a clone of the cached model
      const model = this.cloneModel(this.modelCache[modelType]);

      // Process any needed post-loading tasks
      this.setupModel(model, modelType);

      // Call the success callback
      if (onLoad) {
        setTimeout(() => onLoad(model), 0);
      }
      return;
    }

    // Load the model
    this.gltfLoader.load(modelPath, gltf => {
      if (this.debug) console.log(`[ModelLoader] Successfully loaded: ${modelType}`, gltf);

      // Get the main scene from the GLTF
      const model = gltf.scene;

      // Set up the model properly
      this.setupModel(model, modelType);

      // Store in cache
      this.modelCache[modelType] = this.cloneModel(model);

      // Call the success callback
      if (onLoad) onLoad(model);

      // Dispatch loading completed event
      const completeEvent = new CustomEvent('model-loading-completed', {
        detail: {
          modelType,
          modelPath,
          model
        }
      });
      window.dispatchEvent(completeEvent);
    }, progress => {
      // Progress callback
      const percentComplete = progress.loaded / progress.total * 100;
      if (this.debug && percentComplete % 20 < 1) {
        console.log(`[ModelLoader] Loading ${modelType}: ${Math.round(percentComplete)}%`);
      }
    }, error => {
      console.error(`[ModelLoader] Error loading ${modelType}:`, error);

      // Create a fallback model
      if (onLoad) {
        const fallbackModel = this.createFallbackModel(modelType);
        onLoad(fallbackModel);
      }

      // Call error callback if provided
      if (onError) onError(error);

      // Dispatch loading error event
      const errorEvent = new CustomEvent('model-loading-error', {
        detail: {
          modelType,
          modelPath,
          error
        }
      });
      window.dispatchEvent(errorEvent);
    });
  }

  /**
   * Set up the model after loading
   * @param {THREE.Object3D} model - The loaded model
   * @param {string} modelType - Type of model
   */
  setupModel(model, modelType) {
    // Add model metadata
    model.userData.type = modelType;
    model.userData.isModelRoot = true;
    model.userData.selectable = true;

    // Fix materials and shadows on all meshes
    let meshCount = 0;
    model.traverse(node => {
      if (node.isMesh) {
        meshCount++;

        // Enable shadows
        node.castShadow = true;
        node.receiveShadow = true;

        // Fix materials
        if (node.material) {
          // Handle array of materials
          const materials = Array.isArray(node.material) ? node.material : [node.material];
          materials.forEach(material => {
            // Ensure material is properly set up
            material.side = THREE.DoubleSide; // Show both sides
            material.transparent = material.transparent || false;
            material.opacity = material.opacity !== undefined ? material.opacity : 1.0;

            // Force material to update
            material.needsUpdate = true;

            // Fix potential shader uniform issues
            if (material.type === 'ShaderMaterial' || material.type === 'RawShaderMaterial') {
              if (material.uniforms) {
                Object.keys(material.uniforms).forEach(key => {
                  if (material.uniforms[key] === undefined) {
                    material.uniforms[key] = {
                      value: null
                    };
                  } else if (material.uniforms[key].value === undefined) {
                    material.uniforms[key].value = null;
                  }
                });
              }
            }
          });
        }
      }
    });
    if (this.debug) console.log(`[ModelLoader] Model contains ${meshCount} meshes`);

    // Center the model
    this.centerModel(model);
  }

  /**
   * Center model and place it on the ground
   * @param {THREE.Object3D} model - The model to center
   */
  centerModel(model) {
    // Calculate bounding box
    const box = new THREE.Box3().setFromObject(model);

    // Skip if the box is invalid (can happen with empty models)
    if (box.min.x === Infinity || box.max.x === -Infinity) {
      console.warn('[ModelLoader] Could not calculate bounding box - model may be empty');
      return model;
    }
    const center = box.getCenter(new THREE.Vector3());
    const size = box.getSize(new THREE.Vector3());

    // Calculate offset to place model on the ground
    const yOffset = size.y / 2;

    // Center horizontally, place on ground
    model.position.x = -center.x;
    model.position.z = -center.z;
    model.position.y = -center.y + yOffset;
    return model;
  }

  /**
   * Create a deep clone of a model
   * @param {THREE.Object3D} originalModel - The model to clone
   * @returns {THREE.Object3D} - Cloned model
   */
  cloneModel(originalModel) {
    const clone = originalModel.clone();

    // Deep clone materials to avoid shared material issues
    clone.traverse(node => {
      if (node.isMesh && node.material) {
        if (Array.isArray(node.material)) {
          node.material = node.material.map(mat => mat.clone());
        } else {
          node.material = node.material.clone();
        }
      }
    });

    // Copy user data
    clone.userData = JSON.parse(JSON.stringify(originalModel.userData));
    return clone;
  }

  /**
   * Create a fallback model when loading fails
   * @param {string} modelType - Type of model
   * @returns {THREE.Object3D} - Fallback model
   */
  createFallbackModel(modelType) {
    console.warn(`[ModelLoader] Creating fallback for: ${modelType}`);

    // Create a simple box geometry
    const geometry = new THREE.BoxGeometry(1, 0.5, 1.5);
    const material = new THREE.MeshStandardMaterial({
      color: 0x888888,
      transparent: true,
      opacity: 0.7,
      wireframe: false
    });
    const mesh = new THREE.Mesh(geometry, material);
    mesh.castShadow = true;
    mesh.receiveShadow = true;

    // Create a group to hold the mesh
    const group = new THREE.Group();
    group.add(mesh);

    // Add metadata
    group.userData.type = modelType;
    group.userData.isModelRoot = true;
    group.userData.selectable = true;
    group.userData.isFallback = true;
    return group;
  }

  /**
   * Duplicate an existing object
   * @param {THREE.Object3D} originalObject - The object to duplicate
   * @param {Function} onComplete - Callback with the duplicated object
   */
  duplicate(originalObject, onComplete) {
    if (!originalObject) {
      console.error('[ModelLoader] Cannot duplicate undefined object');
      return;
    }
    const modelType = originalObject.userData.type;
    if (this.modelCache[modelType]) {
      // Create a clone from the cache
      const clone = this.cloneModel(this.modelCache[modelType]);

      // Copy transformation from original
      clone.position.copy(originalObject.position);
      clone.rotation.copy(originalObject.rotation);
      clone.scale.copy(originalObject.scale);
      if (onComplete) onComplete(clone);
    } else {
      console.warn(`[ModelLoader] Cannot duplicate model ${modelType}: not found in cache`);

      // Create a fallback
      const fallback = this.createFallbackModel(modelType);

      // Copy transformation from original
      fallback.position.copy(originalObject.position);
      fallback.rotation.copy(originalObject.rotation);
      fallback.scale.copy(originalObject.scale);
      if (onComplete) onComplete(fallback);
    }
  }
}

