    this.centerModel(model);
  }
  
  /**
   * Center model and place it on the ground
   * @param {THREE.Object3D} model - The model to center
   */
  centerModel(model) {
    // Calculate bounding box
    const box = new THREE.Box3().setFromObject(model);
    
    // Skip if the box is invalid (can happen with empty models)
    if (box.min.x === Infinity || box.max.x === -Infinity) {
